//vip.opstream16.com/20230309/32830_c199a270/index.m3u8"},{"name":"23","slug":"23","filename":"Tuyet Phoi E23","link_embed":"https://vip.opstream16.com/share/326a8605975106f1672c912bd16b4e7b","link_m3u8":"https://vip.opstream16.com/20230310/32881_169de307/index.m3u8"},{"name":"24","slug":"24","filename":"Tuyet Phoi E24","link_embed":"https://vip.opstream16.com/share/90918c5b8c17f80e32d5b155a7bf6197","link_m3u8":"https://vip.opstream16.com/20230310/32882_0ddfd664/index.m3u8"}]}],"time":"25 phút/tập","description":"<p>Tuyệt Phối Tô Tâm Đường sắp lên sóng tại iQIYI. Phim được chuyển thể từ bộ truyện tranh \\\"Tôi Bị Tổng Tài Anti Rồi\\\" và kể về câu chuyện của ngôi sao nhạc pop đình đám Đường Tô bị hiểu nhầm và bị đưa vào tình trạng tạm ngưng hoạt động nghệ thuật, sau đó tăng cân đến 50 kg và trở thành người giúp việc trực tiếp của Hoàng Phủ Quyết - chủ tịch của một tập đoàn giải trí. Thật không ngờ, Hoàng Phủ Quyết, người bị mù mặt lại chính là fan hâm mộ số một của Tang Tố.\\n\\nVì vậy, hai người đã bắt đầu một câu chuyện tình yêu vô cùng hài hước và nghịch ngợm khi Hoàng Phủ Quyết muốn \\\"anti\\\" cô nàng ngôi sao tăng cân và \\\"trục xuất\\\" cô khỏi công ty. Những tình huống dở khóc dở cười đã xảy ra khi Đường Tô cố gắng lấy lại tên tuổi của mình trong khi đối đầu với Hoàng Phủ Quyết.</p>","tmdb":{"type":"tv","id":"221379","season":1,"vote_average":6,"vote_count":1},"modified":"2023-03-10T19:16:36.000Z","_image_preserved":true},{"id":"63ff7011de214d41eff1a163","_id":"63ff7011de214d41eff1a163","title":"When Trumpets Fade","origin_name":"When Trumpets Fade","slug":"when-trumpets-fade","year":1998,"type":"single","genre":[{"id":"620a2253e0fc277084dfd339","name":"Chiến Tranh","slug":"chien-tranh"},{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"When Trumpets Fade - 1998","link_embed":"https://vip.opstream14.com/share/5d4c7bf4ebab441c07f4fa26c4f0c4c3","link_m3u8":"https://vip.opstream14.com/20230301/33149_04f7a3c4/index.m3u8"}]}],"time":"95 Phút","description":"<p>Ở Tây Đức trong Thế chiến thứ hai, Binh nhì David Manning miễn cưỡng bỏ lại một đồng đội bị trọng thương và tìm kiếm những người sống sót trong trung đội của anh ta, chỉ để biết được từ sĩ quan chỉ huy Đại úy Pritchett rằng tất cả họ đều đã thiệt mạng trong chiến đấu. Mặc dù yêu cầu giải ngũ với lý do thiểu năng trí tuệ, Manning được thăng cấp trung sĩ và được giao nhiệm vụ lãnh đạo một trung đội mới gồm những người trẻ tuổi được tuyển chọn.</p>","tmdb":{"type":"movie","id":"13935","season":null,"vote_average":6.642,"vote_count":141},"modified":"2023-03-01T22:32:33.000Z","_image_preserved":true},{"id":"63ff7088de214d41eff1b31d","_id":"63ff7088de214d41eff1b31d","title":"Phố Wall","origin_name":"Wall Street","slug":"pho-wall","year":1987,"type":"single","genre":[{"id":"620a2249e0fc277084dfd2e5","name":"Hình Sự","slug":"hinh-su"},{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Wall Street - 1987","link_embed":"https://vip.opstream14.com/share/1a4461e3ca15c1b7c5b322f161cdcf0b","link_m3u8":"https://vip.opstream14.com/20230301/33137_38435494/index.m3u8"}]}],"time":"126 Phút","description":"<p>Một nhà môi giới chứng khoán trẻ tuổi và thiếu kiên nhẫn sẵn sàng làm bất cứ điều gì để đạt được vị trí dẫn đầu, kể cả giao dịch dựa trên thông tin nội bộ bất hợp pháp được lấy từ một kẻ cướp công ty tham lam và tàn nhẫn, kẻ luôn thu phục thanh niên dưới trướng của mình.</p>","tmdb":{"type":"movie","id":"10673","season":null,"vote_average":7.164,"vote_count":2171},"modified":"2023-03-01T22:34:32.000Z","_image_preserved":true},{"id":"63ff70e4de214d41eff1c2bf","_id":"63ff70e4de214d41eff1c2bf","title":"Thị trấn Tombstone","origin_name":"Tombstone","slug":"thi-tran-tombstone","year":1993,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Tombstone - 1993","link_embed":"https://vip.opstream14.com/share/607e79272c337728322fe13f83866c17","link_m3u8":"https://vip.opstream14.com/20230301/33132_53d3d8a0/index.m3u8"}]}],"time":"130 Phút","description":"<p>Nguyên soái huyền thoại Wyatt Earp, hiện là một tay súng mệt mỏi, tham gia cùng các anh trai Morgan và Virgil để theo đuổi vận may chung của họ tại thị trấn khai thác mỏ Tombstone thịnh vượng. Nhưng Earp buộc phải đeo huy hiệu một lần nữa và nhận được sự giúp đỡ từ người bạn khét tiếng Doc Holliday của mình khi một băng đảng gồm những tên cướp và kẻ trộm phản bội bắt đầu khủng bố thị trấn.</p>","tmdb":{"type":"movie","id":"11969","season":null,"vote_average":7.579,"vote_count":2315},"modified":"2023-03-01T22:36:04.000Z","_image_preserved":true},{"id":"63ff715cde214d41eff1e0ab","_id":"63ff715cde214d41eff1e0ab","title":"Mối Tình Tay Ba","origin_name":"The Unbearable Lightness of Being","slug":"moi-tinh-tay-ba","year":1988,"type":"single","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620a221de0fc277084dfd1c1","name":"Hài Hước","slug":"hai-huoc"},{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"The Unbearable Lightness of Being - 1988","link_embed":"https://vip.opstream14.com/share/bc6413b0348aeeed0bbc0836604acc75","link_m3u8":"https://vip.opstream14.com/20230301/33128_a28d5c85/index.m3u8"}]}],"time":"171 Phút","description":"<p>Bác sĩ phẫu thuật thành công Tomas rời Praha để phẫu thuật, gặp một nhiếp ảnh gia trẻ tên là Tereza và đưa cô ấy trở lại với anh ta. Tereza ngạc nhiên khi biết Tomas đã có quan hệ tình cảm với Sabina phóng túng, nhưng khi cuộc xâm lược của Liên Xô xảy ra, cả ba người đều trốn sang Thụy Sĩ. Sabina bắt đầu ngoại tình, Tom tiếp tục lăng nhăng, và Tereza chán ghét trở về Tiệp Khắc. Nhận ra sai lầm của mình, Tomas quyết định đuổi theo cô.</p>","tmdb":{"type":"movie","id":"10644","season":null,"vote_average":6.89,"vote_count":488},"modified":"2023-03-01T22:38:04.000Z","_image_preserved":true},{"id":"63ff71d4de214d41eff1f704","_id":"63ff71d4de214d41eff1f704","title":"Mảnh Đời Kỳ Lạ Của Timothy Green","origin_name":"The Odd Life of Timothy Green","slug":"manh-doi-ky-la-cua-timothy-green","year":2012,"type":"single","genre":[{"id":"620a221de0fc277084dfd1c1","name":"Hài Hước","slug":"hai-huoc"},{"id":"620e4c0b6ba8271c5eef05a8","name":"Gia Đình","slug":"gia-dinh"},{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"The Odd Life of Timothy Green - 2012","link_embed":"https://vip.opstream14.com/share/5c3507b72dec5e4f097906ccf9df0c88","link_m3u8":"https://vip.opstream14.com/20230301/33123_1e73d785/index.m3u8"}]}],"time":"105 Phút","description":"<p>Chuyện phim kể về một cặp vợ chồng hạnh phúc, Cindy và Jim, nhưng lại hiếm muộn. Họ vẫn mong ước hàng đêm mình sẽ trở thành cha, mẹ thực sự nhưng điều đó dường như quá xa vời. Một ngày nọ, Cindy và Jim viết tất cả ý tưởng mà họ mường tượng về đứa con tương lai rồi cho vào một chiếc hộp và chôn ở vườn sau nhà. Trong đêm mưa bão, cậu bé Timothy xuất hiện như một món quà bất ngờ dành cho đôi vợ chồng hiếm muộn. Tuy nhiên, ở đôi chân của cậu bé lại mọc lên những chiếc lá xanh tươi khác thường.</p>","tmdb":{"type":"movie","id":"71864","season":null,"vote_average":6.994,"vote_count":1222},"modified":"2023-03-01T22:40:04.000Z","_image_preserved":true},{"id":"63ff7451de214d41eff27a17","_id":"63ff7451de214d41eff27a17","title":"Nữ Công Tước","origin_name":"The Duchess","slug":"nu-cong-tuoc","year":2008,"type":"single","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"The Duchess - 2008","link_embed":"https://vip.opstream14.com/share/28364247e6496328782352c6d1cea205","link_m3u8":"https://vip.opstream14.com/20230301/33122_adeabb9b/index.m3u8"}]}],"time":"110 Phút","description":"<p>Một biên niên sử về cuộc đời của quý tộc thế kỷ 18 Georgiana, Nữ công tước xứ Devonshire, người bị nguyền rủa vì cuộc sống cá nhân và chính trị xa hoa của mình.</p>","tmdb":{"type":"movie","id":"12783","season":null,"vote_average":7,"vote_count":1740},"modified":"2023-03-01T22:50:41.000Z","_image_preserved":true},{"id":"63ff74b8de214d41eff29006","_id":"63ff74b8de214d41eff29006","title":"Người Hùng Trở Về","origin_name":"Returner","slug":"nguoi-hung-tro-ve","year":2002,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"},{"id":"620a2282e0fc277084dfd435","name":"Viễn Tưởng","slug":"vien-tuong"},{"id":"620a2293e0fc277084dfd489","name":"Phiêu Lưu","slug":"phieu-luu"}],"country":[{"id":"620a2307e0fc277084dfd726","name":"Nhật Bản","slug":"nhat-ban"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Returner - 2002","link_embed":"https://vip.opstream14.com/share/6bf031c5f3624fce713d35a8789cef8f","link_m3u8":"https://vip.opstream14.com/20230301/33121_cfbd3a4f/index.m3u8"}]}],"time":"116 Phút","description":"<p>Sau khi một cuộc xâm lược của người ngoài hành tinh đe dọa hủy diệt loài người, một cô gái trẻ người Nhật, tên là Milly, du hành ngược thời gian từ năm 2084 đến tháng 10 năm 2002, và nhờ sự trợ giúp bất đắc dĩ của tay súng lão luyện ở Tokyo, tên là Miyamoto, để khám phá và ngăn chặn sự khởi đầu của cuộc xâm lược. chiến tranh. Tuy nhiên, rắc rối xảy ra khi hai nhân vật chính buộc phải đối phó với một trùm mafia Nhật Bản, tên là Mizoguchi, người bằng cách nào đó đã tham gia vào việc bắt đầu cuộc chiến bằng cách giam giữ con tàu vũ trụ đầu tiên của người ngoài hành tinh và phi công người ngoài hành tinh của nó, trong khi hai anh hùng của chúng ta chạy đua chống lại đồng hồ để tìm cách ngăn chặn sự hủy diệt sắp tới từ hạm đội xâm lược của người ngoài hành tinh đang tìm cách báo thù trên đường đến Trái đất.</p>","tmdb":{"type"